import React, { useState, useEffect } from 'react';
import { toast } from 'react-hot-toast';
import { Phone, Layout, ArrowLeft, RefreshCw } from 'lucide-react';
import './Auth.css';

const Auth = ({ onLogin }) => {
  const [step, setStep] = useState('PHONE'); // PHONE or OTP
  const [phoneNumber, setPhoneNumber] = useState('');
  const [otp, setOtp] = useState(['', '', '', '', '', '']);
  const [timer, setTimer] = useState(30);
  const [canResend, setCanResend] = useState(false);

  useEffect(() => {
    let interval;
    if (step === 'OTP' && timer > 0) {
      interval = setInterval(() => {
        setTimer((prev) => prev - 1);
      }, 1000);
    } else if (timer === 0) {
      setCanResend(true);
      clearInterval(interval);
    }
    return () => clearInterval(interval);
  }, [step, timer]);

  const handleSendOTP = () => {
    if (phoneNumber.length === 10) {
      toast.success('OTP sent to +91 ' + phoneNumber);
      setStep('OTP');
      setTimer(30);
      setCanResend(false);
    } else {
      toast.error('Please enter a valid 10-digit number');
    }
  };

  const handleOtpChange = (element, index) => {
    if (isNaN(element.value)) return false;

    setOtp([...otp.map((d, idx) => (idx === index ? element.value : d))]);

    // Focus next input
    if (element.nextSibling && element.value !== '') {
      element.nextSibling.focus();
    }
  };

  const handleVerifyOTP = () => {
    const otpValue = otp.join('');
    if (otpValue.length === 6) {
      toast.success('Verification successful!');
      setTimeout(() => onLogin(), 1000);
    } else {
      toast.error('Please enter the 6-digit OTP');
    }
  };

  const handleResendOTP = () => {
    if (canResend) {
      setTimer(30);
      setCanResend(false);
      toast.success('New OTP sent!');
    }
  };

  const handleGoogleLogin = () => {
    toast.loading('Redirecting to Google...', { id: 'google-auth' });
    setTimeout(() => {
      toast.success('Logged in with Google', { id: 'google-auth' });
      onLogin();
    }, 1500);
  };

  return (
    <div className="auth-page animate-fade-in">
        <div className="auth-container glass">
           <div className="auth-illustration">
              <img src="/login_illustration.png" alt="Community" />
           </div>

           <div className="auth-content">
              {step === 'PHONE' ? (
                <>
                  <h2>Welcome to Passwala</h2>
                  <p>Your Neighborhood, Powered by AI</p>

                  <div className="social-login">
                     <button className="social-btn google-btn" onClick={handleGoogleLogin}>
                        <img src="https://www.gstatic.com/firebasejs/ui/2.0.0/images/auth/google.svg" alt="Google" width="18" />
                        Continue with Google
                     </button>
                  </div>

                  <div className="divider">
                     <span>OR</span>
                  </div>

                  <div className="phone-login">
                     <div className="input-group">
                        <div className="country-code">+91</div>
                        <input 
                          type="tel" 
                          placeholder="Phone Number" 
                          maxLength={10}
                          value={phoneNumber}
                          onChange={(e) => setPhoneNumber(e.target.value)}
                        />
                     </div>
                     <button className="auth-submit-btn" onClick={handleSendOTP}>
                        Send OTP
                     </button>
                  </div>
                </>
              ) : (
                <div className="otp-flow">
                  <button className="back-btn" onClick={() => setStep('PHONE')}>
                    <ArrowLeft size={20} />
                  </button>
                  <h2>Verify Number</h2>
                  <p>Enter the 6-digit code sent to +91 {phoneNumber}</p>

                  <div className="otp-input-container">
                    {otp.map((data, index) => (
                      <input
                        className="otp-field"
                        type="text"
                        name="otp"
                        maxLength="1"
                        key={index}
                        value={data}
                        onChange={(e) => handleOtpChange(e.target, index)}
                        onFocus={(e) => e.target.select()}
                      />
                    ))}
                  </div>

                  <button className="auth-submit-btn" onClick={handleVerifyOTP}>
                    Verify & Proceed
                  </button>

                  <div className="resend-container">
                    {canResend ? (
                      <button className="resend-btn" onClick={handleResendOTP}>
                        <RefreshCw size={14} /> Resend OTP
                      </button>
                    ) : (
                      <span className="timer-text">Resend in {timer}s</span>
                    )}
                  </div>
                </div>
              )}

              <p className="auth-footer">By continuing, you agree to our Terms & Conditions</p>
           </div>
        </div>
    </div>
  );
};

export default Auth;
